/**
 * Placeholder React Query hooks for dietary tag API.
 *
 * These hooks wrap manual fetch calls until the backend Swagger spec
 * is regenerated via Orval. Once generated, replace these with the
 * auto-generated hooks from @/server/autoGeneratedHooks/onlinemenu.
 */
import { useCallback } from 'react';

import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';

import env from '../../../../config/environment';
import { get, post, deleteMethod } from '../../../http/utils/methods';

import type { DietaryTagDto, CreateDietaryTagRequest } from '../types';

const API_URL = env.API_URL;

const QUERY_KEY_ADMIN = ['dietary-tags'] as const;
const QUERY_KEY_PUBLIC = ['dietary-tags', 'public'] as const;

async function fetchDietaryTags(): Promise<DietaryTagDto[]> {
  return get<undefined, DietaryTagDto[]>('/api/dietary-tags', undefined, {
    withToken: true,
    withCredentials: true,
    baseURL: API_URL,
  });
}

async function fetchPublicDietaryTags(): Promise<DietaryTagDto[]> {
  return get<undefined, DietaryTagDto[]>('/public/dietary-tags', undefined, {
    withToken: false,
    withCredentials: false,
    baseURL: API_URL,
  });
}

async function createDietaryTag(request: CreateDietaryTagRequest): Promise<DietaryTagDto> {
  return post<CreateDietaryTagRequest, DietaryTagDto>('/api/dietary-tags', request, {
    withToken: true,
    withCredentials: true,
    baseURL: API_URL,
  });
}

async function deleteDietaryTag(externalId: string): Promise<undefined> {
  return deleteMethod<undefined, undefined>(`/api/dietary-tags/${externalId}`, undefined, {
    withToken: true,
    withCredentials: true,
    baseURL: API_URL,
  });
}

export function getDietaryTagsQueryKey(): readonly string[] {
  return QUERY_KEY_ADMIN;
}

export function getPublicDietaryTagsQueryKey(): readonly string[] {
  return QUERY_KEY_PUBLIC;
}

export function useGetDietaryTags(): {
  data: DietaryTagDto[] | undefined;
  isLoading: boolean;
  isError: boolean;
  error: Error | null;
} {
  const query = useQuery({
    queryKey: [...QUERY_KEY_ADMIN],
    queryFn: fetchDietaryTags,
  });
  const queryError: unknown = query.error;
  return {
    data: query.data,
    isLoading: query.isLoading,
    isError: query.isError,
    error: queryError instanceof Error ? queryError : null,
  };
}

export function useGetPublicDietaryTags(): {
  data: DietaryTagDto[] | undefined;
  isLoading: boolean;
  isError: boolean;
  error: Error | null;
} {
  const query = useQuery({
    queryKey: [...QUERY_KEY_PUBLIC],
    queryFn: fetchPublicDietaryTags,
  });
  const queryError: unknown = query.error;
  return {
    data: query.data,
    isLoading: query.isLoading,
    isError: query.isError,
    error: queryError instanceof Error ? queryError : null,
  };
}

interface MutationCallbacks {
  onSuccess?: () => void;
  onError?: (error: Error) => void;
}

export function useCreateDietaryTag(callbacks?: MutationCallbacks): {
  createTag: (request: CreateDietaryTagRequest) => void;
  isPending: boolean;
  isError: boolean;
  error: Error | null;
} {
  const queryClient = useQueryClient();
  const mutation = useMutation({
    mutationFn: createDietaryTag,
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: [...QUERY_KEY_ADMIN] }).catch(() => {});
      callbacks?.onSuccess?.();
    },
    onError: (error: unknown) => {
      const errorObj = error instanceof Error ? error : new Error('Create failed');
      callbacks?.onError?.(errorObj);
    },
  });

  const createTag = useCallback(
    (request: CreateDietaryTagRequest) => mutation.mutate(request),
    [mutation],
  );

  const mutationError: unknown = mutation.error;
  return {
    createTag,
    isPending: mutation.isPending,
    isError: mutation.isError,
    error: mutationError instanceof Error ? mutationError : null,
  };
}

export function useDeleteDietaryTag(callbacks?: MutationCallbacks): {
  deleteTag: (externalId: string) => void;
  isPending: boolean;
  isError: boolean;
  error: Error | null;
} {
  const queryClient = useQueryClient();
  const mutation = useMutation({
    mutationFn: deleteDietaryTag,
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: [...QUERY_KEY_ADMIN] }).catch(() => {});
      callbacks?.onSuccess?.();
    },
    onError: (error: unknown) => {
      const errorObj = error instanceof Error ? error : new Error('Delete failed');
      callbacks?.onError?.(errorObj);
    },
  });

  const deleteTag = useCallback(
    (externalId: string) => mutation.mutate(externalId),
    [mutation],
  );

  const mutationError: unknown = mutation.error;
  return {
    deleteTag,
    isPending: mutation.isPending,
    isError: mutation.isError,
    error: mutationError instanceof Error ? mutationError : null,
  };
}
